"use client";

import { motion } from "framer-motion";
import { useEffect, useState } from "react";
import { techStack } from "@/lib/data";
import AnimatedSection from "@/components/ui/AnimatedSection";
import SectionLabel from "@/components/ui/SectionLabel";

export default function TechCarousel() {
  const [isClient, setIsClient] = useState(false);

  useEffect(() => {
    setIsClient(true);
  }, []);

  if (!isClient) {
    return null;
  }

  return (
    <section
      data-section="tech-carousel"
      className="py-24 bg-card-bg/85 relative overflow-hidden"
    >
      {/* Decorative elements */}
      <div className="absolute inset-0 pointer-events-none">
        <div className="absolute top-0 right-0 w-96 h-96 rounded-full bg-primary/[0.03] blur-3xl" />
        <div className="absolute bottom-0 left-0 w-96 h-96 rounded-full bg-accent/[0.03] blur-3xl" />
      </div>

      <div className="max-w-7xl mx-auto px-6 relative z-10">
        <AnimatedSection className="text-center mb-16">
          <SectionLabel label="Our Tech Stack" className="justify-center" />
          <h2 className="text-3xl md:text-4xl font-bold tracking-tight mt-4">
            Technologies We <span className="gradient-text">Use</span>
          </h2>
          <p className="text-muted mt-4 max-w-2xl mx-auto">
            We use proven tools and platforms to deliver reliable, future-ready
            websites and applications tailored to your business needs.
          </p>
        </AnimatedSection>

        {/* Tech Stack Grid */}
        <div className="space-y-12">
          {techStack.map((category, categoryIndex) => (
            <motion.div
              key={category.title}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: categoryIndex * 0.1 }}
              viewport={{ once: true, margin: "-100px" }}
            >
              <h3 className="text-sm font-bold tracking-widest text-primary mb-6 uppercase">
                {category.title}
              </h3>
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
                {category.items.map((tech, index) => (
                  <motion.div
                    key={tech.name}
                    initial={{ opacity: 0, scale: 0.9 }}
                    whileInView={{ opacity: 1, scale: 1 }}
                    transition={{ duration: 0.3, delay: index * 0.05 }}
                    viewport={{ once: true, margin: "-50px" }}
                    whileHover={{ y: -4, scale: 1.05 }}
                    className="bg-section-bg rounded-lg p-4 border border-border hover:border-primary/50 transition-colors duration-300 flex flex-col items-center justify-center text-center group cursor-pointer"
                  >
                    <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-all duration-300 mb-3 flex-shrink-0">
                      <TechIcon name={tech.icon} />
                    </div>
                    <span className="text-sm font-semibold text-foreground">
                      {tech.name}
                    </span>
                  </motion.div>
                ))}
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

